import java.util.*;
import java.util.regex.*;

public class PlaceholderReplacer {

    /**
     * Replaces all occurrences of {key} in `text` with the value that
     * is stored under that key in the supplied map.
     *
     * @param text the string that may contain placeholders surrounded by { }
     * @param values a map that contains the replacement strings
     * @return the string after all replacements have been made
     */
    public static String replace(String text, Map<String, String> values) {
        // Pattern that matches :  {   any characters that are not }   }
        Pattern p = Pattern.compile("\\{([^}]*)\\}");
        Matcher m = p.matcher(text);

        StringBuffer sb = new StringBuffer();
        while (m.find()) {
            String key  = m.group(1);                  // the text inside {}
            String repl = values.getOrDefault(key, "{}"); // keep {} if key not found
            // Escape $ signs etc. that may appear in the replacement String
            repl = Matcher.quoteReplacement(repl);
            m.appendReplacement(sb, repl);
        }
        m.appendTail(sb);
        return sb.toString();
    }

